// Calcula los 3 posts de la próxima semana (Lun=Historia, Mié=Carrusel, Vie=Reel)
// y construye el prompt para Claude, siguiendo content-strategy.md y master-copy-prompt.md.
const raw = $input.first().json;
const arr = Array.isArray(raw) ? raw : (raw && raw.data ? raw.data : (raw ? [raw] : []));
const last = arr[0];
const lastDia = last ? Number(last.dia_narrativo) : 0;
const lastWeek = last ? Number(last.semana) : 0;

const ARCS = ['problema', 'realidad', 'solucion', 'prueba'];
const nextWeek = lastWeek ? (lastWeek % 4) + 1 : 1;
const arc = ARCS[(nextWeek - 1) % 4];
const isOddWeek = nextWeek % 2 === 1;

// Próximo lunes a partir de hoy (el trigger corre el domingo 20:00 -> al día siguiente).
const now = new Date();
const monday = new Date(now);
monday.setDate(now.getDate() + ((1 + 7 - now.getDay()) % 7 || 7));
const iso = (d) => d.toISOString().slice(0, 10);
const wednesday = new Date(monday); wednesday.setDate(monday.getDate() + 2);
const friday = new Date(monday); friday.setDate(monday.getDate() + 4);

const slots = [
  { date: iso(monday), day_label: 'Lunes', format: 'Historia', pilar: isOddWeek ? 1 : 2, dia_narrativo: lastDia + 1, semana: nextWeek, arc },
  { date: iso(wednesday), day_label: 'Miércoles', format: 'Carrusel', pilar: isOddWeek ? 4 : 1, dia_narrativo: lastDia + 2, semana: nextWeek, arc },
  { date: iso(friday), day_label: 'Viernes', format: 'Reel', pilar: isOddWeek ? 5 : 3, dia_narrativo: lastDia + 3, semana: nextWeek, arc },
];

const PILAR_LABEL = {
  1: 'P1 — SEO/Google: si no aparecés en Google, no existís',
  2: 'P2 — Organización: organización = tiempo = libertad',
  3: 'P3 — Fidelización: el cliente que vuelve > el que viene una vez',
  4: 'P4 — Errores comunes: situaciones donde el dueño se reconoce',
  5: 'P5 — Casos reales: Tcocina, Doña Clara, La Ventera',
};
const ARC_LABEL = {
  problema: 'El problema (que el dueño se reconozca en su dolor)',
  realidad: 'La realidad (consecuencias de no resolverlo)',
  solucion: 'La solución (cómo BLStudio lo resuelve)',
  prueba: 'La prueba + cierre (casos reales + CTA)',
};

const systemPrompt = `Sos el redactor de BLStudio (@blstudioarg2026), un sistema de gestión para negocios gastronómicos en Argentina.

CONTEXTO DE MARCA
- Tono: aliado directo, argentino, de igual a igual, sin chamuyo técnico, sin humo.
- Evitar: "diseño web", "stack", "framework", "solución tecnológica", "gurú".
- Usar: sistema, pedidos, clientes, plata, que funciona.
- A quién le habla: dueño de hamburguesería / casa de comidas en Argentina. Dolores: no aparece en Google, pedidos por WhatsApp (caos), no fideliza, miedo a lo digital.

REGLAS DE COPY
- SIN nombres propios de personas. A los dueños se los nombra por rol ("el dueño", "la dueña") o por el negocio (Tcocina, Doña Clara, La Ventera). Los negocios sí se nombran.
- Hook directo en la primera línea, que el dueño se reconozca o se frene a leer.
- 1 idea por pieza. Sin relleno. Frases cortas.
- Ejemplos reales > teoría: Tcocina (150 pedidos un domingo sin errores), Doña Clara (rotisería de 20 años digitalizada en 2 semanas, $2M ARS), aceitelaventera.com (primero en Google).
- CTA simple al final: "¿Querés esto para tu negocio? Respondé esta historia / mandá MD". Sin formularios.
- Caption: 4-8 líneas. Para Carrusel/Reel sumar slide_texts (array de strings, uno por slide/escena).
- Hashtags: 5-8, mezcla de rubro + ubicación + tema.

Devolvé EXCLUSIVAMENTE un JSON array de 3 objetos (sin texto antes ni después), uno por cada post solicitado, con este shape exacto:
[{ "topic": "...", "hook": "...", "caption": "...", "slide_texts": ["..."], "hashtags": ["#..."], "visual_brief": "..." }]`;

const userPrompt = `Generá los 3 posts de la próxima semana (semana ${nextWeek} del ciclo, arco: ${ARC_LABEL[arc]}).\n\n` +
  slots.map((s, i) => `Post ${i + 1} — ${s.day_label} ${s.date} — formato ${s.format} — ${PILAR_LABEL[s.pilar]}`).join('\n');

return [{
  json: {
    anthropic_request: {
      model: $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6',
      max_tokens: 2048,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }],
    },
    slots,
  },
}];

// Parsea la respuesta de Claude (array JSON de 3 posts) y la combina con los
// campos estructurales calculados en 'Calcular próxima semana'.
const response = $input.first().json;
const text = (response.content || []).map(c => c.text || '').join('');

let generated = [];
try {
  generated = JSON.parse(text);
} catch (e) {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) { try { generated = JSON.parse(match[0]); } catch (e2) { generated = []; } }
}

const slots = $('Calcular próxima semana').first().json.slots;

const rows = slots.map((slot, i) => {
  const g = generated[i] || {};
  return {
    date: slot.date,
    dia_narrativo: slot.dia_narrativo,
    semana: slot.semana,
    arc: slot.arc,
    format: slot.format,
    pilar: slot.pilar,
    topic: g.topic || slot.day_label,
    hook: g.hook || '',
    caption: g.caption || '',
    slide_texts: g.slide_texts || null,
    hashtags: g.hashtags || null,
    visual_brief: g.visual_brief || null,
    status: 'copy_ready',
  };
});

return [{ json: { rows } }];
